// n8n Code Node (JavaScript)
// Parse Privacy Governance Agent plain-text output into structured rows

function extractField(text, fieldName) {
  // Matches "fieldName: value" until the next \n or end
  const regex = new RegExp(`${fieldName}\\s*:\\s*(.+?)(?=\\n[a-zA-Z]|$)`, "s");
  const match = text.match(regex);
  return match ? match[1].trim() : "";
}

function extractArray(text, fieldName) {
  // Matches fieldName : ["a", "b"] or fieldName: [\n "a",\n "b"\n]
  const regex = new RegExp(`${fieldName}\\s*:\\s*(\\[[\\s\\S]*?\\])`, "i");
  const match = text.match(regex);
  if (!match) return "";
  try {
    const parsed = JSON.parse(match[1]);
    return Array.isArray(parsed) ? parsed.join(" | ") : match[1];
  } catch {
    return match[1].replace(/[\[\]"]/g, "").trim();
  }
}

function extractActionList(text) {
  // Extracts the recommendedAction array and returns as numbered string
  const regex = /recommendedAction\s*:\s*\[([\s\S]*?)\]/i;
  const match = text.match(regex);
  if (!match) return "";
  try {
    const parsed = JSON.parse(`[${match[1]}]`);
    return parsed.map((a, i) => `${i + 1}. ${a}`).join("\n");
  } catch {
    // Fallback: strip quotes and clean up
    return match[1]
      .split(/",\s*\n\s*"/)
      .map(s => s.replace(/^"|"$/g, "").trim())
      .filter(Boolean)
      .map((a, i) => `${i + 1}. ${a}`)
      .join("\n");
  }
}

return items.flatMap(item => {
  // Your output lives in item.json.output as a plain string
  const raw =
    item.json.output ||
    (item.json.message && (item.json.message.content ?? item.json.message)) ||
    item.json.content ||
    "";

  if (!raw || typeof raw !== "string") return [];

  // Normalize \n literals to real newlines if needed
  const text = raw.replace(/\\n/g, "\n");

  return [{
    json: {
      url:                extractField(text, "URL"),
      riskLevel:          extractField(text, "riskLevel"),
      riskSummary:        extractField(text, "riskSummary"),
      regulatoryFramework: extractArray(text, "regulatoryFramework"),
      recommendedAction:  extractActionList(text)
    }
  }];
});

// n8n Code Node (JavaScript)
// Parse Risk Detection Agent JSON output into structured rows

function stripCodeFences(s) {
  if (!s) return "";
  return s
    .replace(/```json/gi, "")
    .replace(/```/g, "")
    .trim();
}

function tryParseJsonBlock(s) {
  if (!s) return null;
  const trimmed = s.trim();
  if (!(trimmed.startsWith("{") || trimmed.startsWith("["))) return null;
  try {
    return JSON.parse(trimmed);
  } catch (e) {
    const arrMatch = s.match(/\[[\s\S]*\]/);
    if (arrMatch) {
      try { return JSON.parse(arrMatch[0]); } catch(e2) {}
    }
    const start = s.indexOf("{");
    const end = s.lastIndexOf("}");
    if (start !== -1 && end !== -1 && end > start) {
      try { return JSON.parse(s.slice(start, end + 1)); } catch(e3) {}
    }
    return null;
  }
}

function arrToStr(val) {
  if (Array.isArray(val)) return val.join(" | ");
  if (typeof val === "string") return val;
  return "";
}

return items.flatMap(function(item) {
  var raw =
    item.json.output ||
    (item.json.message && (item.json.message.content || item.json.message)) ||
    item.json.content ||
    "";

  if (!raw || typeof raw !== "string") return [];

  var cleaned = stripCodeFences(raw);
  var parsed = tryParseJsonBlock(cleaned);
  if (!parsed) return [];

  return [{
    json: {
      url:                 parsed.url                 || "",
      riskLevel:           parsed.riskLevel           || "",
      riskSummary:         parsed.riskSummary         || "",
      regulatoryFramework: parsed.regulatoryFramework || "",
      recommendedAction:   arrToStr(parsed.recommendedAction),
      detectedRisks:       arrToStr(parsed.detectedRisks),
      urgencyLevel:        parsed.urgencyLevel        || "",
      auditLogEntry:       parsed.auditLogEntry       || "",
      recommendedActions:  arrToStr(parsed.recommendedActions),
      routingDecision:     parsed.routingDecision     || ""
    }
  }];
});
